import React, { useEffect, useState } from "react";
import api from "../api";

export default function AdminDashboard() {
  const [orders, setOrders] = useState([]);
  const token = localStorage.getItem("token");

const fetchOrders = async () => {
  try {
    const res = await api.get("/orders");
    setOrders(res.data);
  } catch (err) {
    console.error(err.response?.data || err.message);
  }
};


  useEffect(() => {
    fetchOrders();
  }, [token]);
const handlePrint = (order) => {
  const printWindow = window.open('', '_blank');
  const itemsHtml = order.items.map(item => `
    <tr>
      <td>${item.food?.name}</td>
      <td>${item.quantity}</td>
      <td>₹${item.food?.price}</td>
      <td>₹${item.food?.price * item.quantity}</td>
    </tr>
  `).join('');

  printWindow.document.write(`
    <html>
      <head>
        <title>Order Bill - ${order.token}</title>
        <style>
          body { font-family: Arial; padding: 20px; }
          h2 { margin-bottom: 10px; }
          table { width: 100%; border-collapse: collapse; }
          th, td { border: 1px solid #ccc; padding: 8px; text-align: left; }
          .total { font-weight: bold; }
        </style>
      </head>
      <body>
        <h2>🧾 Order Bill</h2>
        <p><strong>Order Token:</strong> ${order.token}</p>
        <p><strong>Customer:</strong> ${order.user?.name}</p>
        <p><strong>Status:</strong> ${order.status}</p>
        <p><strong>Payment:</strong> ${order.payment}</p>
        <table>
          <thead>
            <tr>
              <th>Item</th>
              <th>Qty</th>
              <th>Price</th>
              <th>Subtotal</th>
            </tr>
          </thead>
          <tbody>
            ${itemsHtml}
            <tr class="total">
              <td colspan="3">Total</td>
              <td>₹${order.totalPrice}</td>
            </tr>
          </tbody>
        </table>
        <script>
          window.print();
          window.onafterprint = () => window.close();
        </script>
      </body>
    </html>
  `);

  printWindow.document.close();
};

  const updateStatus = async (id, status) => {
    try{
  await api.put(`/orders/${id}/status`, { status });
    fetchOrders();}
    catch(err){
      console.log(err.response?.data||err.message);
    }
  };
  const updatePayment = async (id, payment) => {
  try {
    await api.put(`/orders/${id}/status`, { payment });
    fetchOrders();
  } catch (err) {
    console.error(err.response?.data || err.message);
  }
};

  return (
    <div>
      <h3>orders</h3>
      <table className="table table-striped">
        <thead>
          <tr>
            <th>Token</th>
            <th>Student</th>
            <th>Items</th>
            <th>Status</th>
            <th>Action</th>
          </tr>
        </thead>
        <tbody>
          {orders.map((o) => (
        <tr key={o._id}>
  <td><span className="badge bg-dark">{o.token}</span></td>
  <td>{o.user?.name}</td>
  <td>
    {o.items.map((i) => (
      <div key={i._id}>{i.food?.name} x {i.quantity}</div>
    ))}
  </td>
  <td>
    <span className={`badge ${
      o.status === "Pending" ? "bg-warning" :
      o.status === "Preparing" ? "bg-info" : "bg-success"
    }`}>
      {o.status}
    </span>
  </td>

  {/* Payment Status */}
  <td>
    <span className={`badge ${o.payment === "success" ? "bg-success" : "bg-danger"}`}>
      {o.payment}
    </span>
  </td>

  {/* Status Action */}
  <td>
    <button className="btn btn-sm btn-outline-primary me-2"
      onClick={() => updateStatus(o._id, "Preparing")}>Preparing</button>
    <button className="btn btn-sm btn-outline-success"
      onClick={() => updateStatus(o._id, "Delivered")}>Delivered</button>
  </td>

  {/* Payment Action */}
  <td>
    {o.payment !== "success" && (
      <button className="btn btn-sm btn-outline-success"
        onClick={() => updatePayment(o._id, "success")}>
        Mark as Paid
      </button>
    )}
  </td>
  <td>
    <button
  className="btn btn-sm btn-outline-secondary"
  onClick={() => handlePrint(o)}
>
  🖨️ Print Bill
</button>

  </td>
</tr>

          ))}
        </tbody>
      </table>
    </div>
  );
}
